1	import { test, expect } from '@playwright/test';
2	
3	// DDx Server UI — visual regression screenshots
4	// These capture each page for visual review and regression detection.
5	// Run: bunx playwright test e2e/screenshots.spec.ts --update-snapshots
6	// to update baselines after intentional changes.
7	//
8	// Dark/light parity is a FEAT-008 frontend-design gate
9	// (docs/helix/01-frame/concerns.md#frontend-design). Every page is
10	// snapshotted in both modes; any theme-specific palette drift fails CI.
11	//
12	// Per-project routes resolve their node/project IDs at runtime against
13	// the fixture-backed Go DDx server (see playwright.config.ts) so the
14	// screenshots render seeded fixture data rather than the developer's
15	// live .ddx/ state.
16	
17	// Resolve fixture node + project IDs from the live harness. The fixture
18	// project is the workspace under a `mktemp -d -t ddx-e2e-XXXXXX` path —
19	// other entries in /api/projects (carried over from developer-local state)
20	// must not be picked up here.
21	async function getFixtureIds(
22		request: import('@playwright/test').APIRequestContext
23	): Promise<{ nodeId: string; projectId: string }> {
24		const nodeResp = await request.post('/graphql', {
25			data: { query: '{ nodeInfo { id name } }' }
26		});
27		const nodeBody = (await nodeResp.json()) as {
28			data: { nodeInfo: { id: string; name: string } };
29		};
30		const projectsResp = await request.get('/api/projects');
31		const projects = (await projectsResp.json()) as Array<{ id: string; name: string; path: string }>;
32		const fixture = projects.find((p) => /(^|\/)ddx-e2e-/.test(p.path) || /^ddx-e2e-/.test(p.name));
33		if (!fixture) {
34			throw new Error(
35				`fixture server has no ddx-e2e-* project registered (got: ${projects
36					.map((p) => p.id)
37					.join(', ')})`
38			);
39		}
40		return { nodeId: nodeBody.data.nodeInfo.id, projectId: fixture.id };
41	}
42	
43	type PageSpec = {
44		name: string;
45		ready: string;
46		maskStarted?: boolean;
47		tolerance: number;
48		// Path is resolved per-test so per-project routes can reference the
49		// fixture-derived node/project IDs.
50		path: (ids: { nodeId: string; projectId: string }) => string;
51	};
52	
53	const PAGES: readonly PageSpec[] = [
54		{ path: () => '/', name: 'dashboard', ready: 'h1', maskStarted: true, tolerance: 0.02 },
55		{ path: () => '/beads', name: 'beads-kanban', ready: 'text=OPEN', tolerance: 0.04 },
56		{ path: () => '/documents', name: 'documents', ready: 'h1', tolerance: 0.02 },
57		{ path: () => '/graph', name: 'graph', ready: 'h1', tolerance: 0.06 },
58		{ path: () => '/agent', name: 'agent', ready: 'h1', tolerance: 0.04 },
59		{ path: () => '/personas', name: 'personas', ready: 'text=Personas', tolerance: 0.04 },
60		{
61			path: ({ nodeId, projectId }) => `/nodes/${nodeId}/projects/${projectId}`,
62			name: 'project-overview',
63			ready: 'text=Actions',
64			tolerance: 0.04
65		},
66		{
67			path: ({ nodeId, projectId }) => `/nodes/${nodeId}/projects/${projectId}/plugins`,
68			name: 'plugins',
69			ready: 'text=Plugins',
70			tolerance: 0.04
71		},
72		{
73			// The fixture workspace ships only the `ddx` plugin (see
74			// e2e/fixtures/.ddx/plugins/), so the plugin-detail snapshot drives
75			// that page rather than a developer-local plugin like `helix`.
76			path: ({ nodeId, projectId }) => `/nodes/${nodeId}/projects/${projectId}/plugins/ddx`,
77			name: 'plugin-detail',
78			ready: 'text=Manifest',
79			tolerance: 0.04
80		},
81		{
82			path: ({ nodeId, projectId }) => `/nodes/${nodeId}/projects/${projectId}/efficacy`,
83			name: 'efficacy',
84			ready: 'text=Efficacy',
85			tolerance: 0.04
86		}
87	] as const;
88	
89	const MODES = ['light', 'dark'] as const;
90	
91	test.describe('DDx Server UI Screenshots', () => {
92		for (const mode of MODES) {
93			for (const pg of PAGES) {
94				test(`${pg.name} (${mode})`, async ({ page, request }) => {
95					const ids = await getFixtureIds(request);
96	
97					await page.addInitScript((m) => {
98						window.localStorage.setItem('mode-watcher-mode', m);
99					}, mode);
100	
101					await page.goto(pg.path(ids));
102					await page.waitForSelector(pg.ready);
103					await page.waitForTimeout(500);
104	
105					await expect(page).toHaveScreenshot(`${pg.name}-${mode}.png`, {
106						fullPage: true,
107						maxDiffPixelRatio: pg.tolerance,
108						mask: pg.maskStarted ? [page.locator('text=/^Started:/')] : undefined
109					});
110				});
111			}
112		}
113	});
